```cpp
#include <vector>
#include <cstdlib>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    // Pointer to the first element of each row for fast access
    double **Ap = reinterpret_cast<double**>(A.data());
    double **Bp = reinterpret_cast<double**>(B.data());
    double *xp = x.data();
    double *yp = y.data();
    double *tmp_p = tmp.data();

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double tmp_val = 0.0;
        double y_val   = 0.0;

        const double *Ai = Ap[i];
        const double *Bi = Bp[i];

        for (int j = 0; j < n; ++j) {
            double xj = xp[j];
            tmp_val += Ai[j] * xj;
            y_val   += Bi[j] * xj;
        }

        tmp_p[i] = tmp_val * alpha + y_val * beta;
    }
}
