#include <vector>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trisolv(int n,
		    std::vector<std::vector<double>>& L,
		    std::vector<double>& x,
		    std::vector<double>& b) {
    // create raw pointers to each row of L for fast access
    std::vector<double*> Lrow(n);
    for (int i = 0; i < n; ++i) {
        // L[i] is a contiguous row
        Lrow[i] = L[i].data();
    }

    for (int i = 0; i < n; ++i) {
        double sum = b[i];
        double* Li = Lrow[i];
        for (int j = 0; j < i; ++j) {
            sum -= Li[j] * x[j];
        }
        x[i] = sum / Li[i];
    }
}
