#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {
    /* Parallelise the outer dimension.  Each thread works on a
       distinct row of B, so there are no data races. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        const double* a_row_start = A[i].data();
        double* b_row = B[i].data();

        /* Note: The recurrence uses elements of the *same* column
           of B, but from rows i+1..m-1.  We therefore need to
           access the correct row of B inside the innermost loop. */
        for (int j = 0; j < n; ++j) {
            double sum = 0.0;
            for (int k = i + 1; k < m; ++k) {
                /* A[k][i] is the element in the *i*-th column of row k. */
                sum += A[k][i] * B[k][j];
            }
            b_row[j] = alpha * (B[i][j] + sum);
        }
    }
}
