/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A)
{
    /* Parallelise over the outermost loop (the rows of C).
       Static tiling distributes work evenly across the 8 threads. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
    {
        /* Cache the row of C for faster access */
        double* const cRow = C[i].data();

        /* Scale the symmetric part of C */
        for (int j = 0; j <= i; ++j)
            cRow[j] *= beta;

        /* Accumulate the rank‑m update */
        for (int k = 0; k < m; ++k)
        {
            const double aik = A[i][k] * alpha;          // pre‑multiply by alpha
            for (int j = 0; j <= i; ++j)
                cRow[j] += aik * A[j][k];
        }
    }
}
