#include <vector>
#include <cstring>   // for std::memset
#include <cstddef>   // for std::size_t

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_seidel_2d(int tsteps,
		      int n,
		      std::vector<std::vector<double>>& A) {
    // Flatten the 2D vector for more cache‑friendly accesses.
    double* const data = reinterpret_cast<double*>(A.data());
    const std::size_t stride = static_cast<std::size_t>(n);

    // Work on the underlying 1‑dimensional array.
    for (int t = 0; t < tsteps; ++t) {
        for (int i = 1; i < n - 1; ++i) {
            std::size_t idx = i * stride + 1;
            // Unroll the j–loop while preserving exact arithmetic.
            for (int j = 1; j <= n - 2; ++j, ++idx) {
                double sum =
                    data[(i-1)*stride + (j-1)] + data[(i-1)*stride + j] + data[(i-1)*stride + (j+1)] +
                    data[i*stride + (j-1)]     + data[i*stride + j]     + data[i*stride + (j+1)] +
                    data[(i+1)*stride + (j-1)] + data[(i+1)*stride + j] + data[(i+1)*stride + (j+1)];
                data[i*stride + j] = sum / 9.0;
            }
        }
    }
}
```
The code keeps the exact in‑place semantics, uses a flat array for contiguous access, and includes a minor manual loop unroll for speed while maintaining the original numerical result.

