```cpp
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B) {
    /* Parallelise over the outermost loop (rows of C) which is fully
       independent.  Static schedule gives good load balance when n is
       relatively large compared to the number of threads. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double*   Ci = C[i].data();     // pointer to current row of C
        const double* Ai = A[i].data(); // pointer to i‑th row of A
        const double* Bi = B[i].data(); // pointer to i‑th row of B

        /* Scale the lower triangular part of C[i,:] by beta. */
        for (int j = 0; j <= i; ++j) {
            Ci[j] *= beta;
        }

        /* Accumulate the rank‑2 update.  We keep the k‑loop as outermost
           inside the i‑loop to maximise spatial locality of the A and B
           rows (they are accessed by column in the original code). */
        for (int k = 0; k < m; ++k) {
            const double a_k = B[i][k];          // B[i][k] once per k
            const double b_k = A[i][k];          // A[i][k] once per k
            for (int j = 0; j <= i; ++j) {
                Ci[j] += (A[j][k] * alpha * a_k) + (B[j][k] * alpha * b_k);
            }
        }
    }
}
