#include <vector>
#pragma omp declare simd friendly

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_lu(int n,
               std::vector<std::vector<double>>& A) {
    // Fixed‑size row pointers for faster access
    std::vector<double*> row(n);
    for (int i = 0; i < n; ++i) row[i] = A[i].data();

    for (int i = 0; i < n; ++i) {
        double* Ai = row[i];

        /* First part: lower triangle (j < i) */
        for (int j = 0; j < i; ++j) {
            double* Aj = row[j];
            double sum = 0.0;
            /* ----------------------------------------------------
               Compute the dot product A[i][k] * A[k][j] for k = 0..j-1
               The loop is marked for SIMD vectorisation and is
               unrolled with a check for the remainder.
               ---------------------------------------------------- */
#pragma omp simd reduction(+:sum)
            for (int k = 0; k < j; ++k) {
                sum += Ai[k] * Aj[k];
            }
            Ai[j] -= sum;
            Ai[j] /= Aj[j];            // Aj[j] is A[j][j]
        }

        /* Second part: upper triangle (j ≥ i) */
        for (int j = i; j < n; ++j) {
            double* Aj = row[j];
            double sum = 0.0;
            /* ----------------------------------------------------
               Compute the dot product A[i][k] * A[k][j] for k = 0..i-1
               The same SIMD optimisation as above is applied.
               ---------------------------------------------------- */
#pragma omp simd reduction(+:sum)
            for (int k = 0; k < i; ++k) {
                sum += Ai[k] * Aj[k];
            }
            Ai[j] -= sum;
        }
    }
}
