symm:
```cpp
#include <vector>
#include <cstddef>
#include <omp.h>

/* Kernel re‑implemented with raw pointers, loop re‑ordering and OpenMP
   parallelisation.  The semantics are identical to the original
   function: C := alpha*A*B + beta*C   (A is M×M, B and C are M×N). */

void kernel_symm(
    int                 m,          // number of rows in A and C
    int                 n,          // number of columns in B and C
    double              alpha,
    double              beta,
    std::vector<std::vector<double>>& C,
    std::vector<std::vector<double>>& A,
    std::vector<std::vector<double>>& B)
{
    /* Flatten the 2‑D vectors to 1‑D arrays for cache efficiency.
       The stride is the number of columns (n for C,B and m for A). */
    const std::size_t strideC = n;
    const std::size_t strideB = n;
    const std::size_t strideA = m;

    double* restrict Cp = &C[0][0];
    double* restrict Ap = &A[0][0];
    double* restrict Bp = &B[0][0];

    /* Parallelise the outer-i loop with OpenMP. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double* restrict Ci = Cp + i * strideC;
        double* restrict Ai = Ap + i * strideA;
        double* restrict Bi = Bp + i * strideB;

        for (int j = 0; j < n; ++j) {
            double temp2 = 0.0;
            double* restrict Ckj = Cp + j;          // C[0][j]
            double* restrict Bkj = Bp + j;          // B[0][j]
            double  Bij   = Bi[j];                  // B[i][j]
            double  Aii   = Ai[i];                  // A[i][i]

            for (int k = 0; k < i; ++k) {
                double  Bkj_val = Bkj[k];           // B[k][j]
                double  Akj_val = Ai[k];           // A[i][k]

                /* C[k][j] += alpha * B[i][j] * A[i][k]; */
                Ckj[k] += alpha * Bij * Akj_val;

                /* temp2 += B[k][j] * A[i][k]; */
                temp2 += Bkj_val * Akj_val;
            }

            /* C[i][j] = beta * C[i][j] + alpha*B[i][j]*A[i][i] + alpha*temp2; */
            Ci[j] = beta * Ci[j] + alpha * Bij * Aii + alpha * temp2;
        }
    }
}
