#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z) {

    /* Use raw pointers for fast access. */
    const double *restrict u1p = u1.data();
    const double *restrict v1p = v1.data();
    const double *restrict u2p = u2.data();
    const double *restrict v2p = v2.data();
    const double *restrict yp  = y.data();
    const double *restrict zp  = z.data();

    /* A is a vector of vectors, but we want contiguous access.
       We linearise it on the fly. */
    for (int i = 0; i < n; ++i) {
        double *restrict Ap = A[i].data();
        for (int j = 0; j < n; ++j) {
            Ap[j] += u1p[i] * v1p[j] + u2p[i] * v2p[j];
        }
    }

    /* Parallelise over rows. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = x[i];                    // local copy of x[i]
        for (int j = 0; j < n; ++j) {
            sum += beta * A[j][i] * yp[j];    // use A[j][i] (column access)
        }
        x[i] = sum;                           // write back
    }

    /* Vector addition x += z */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        x[i] += zp[i];
    }

    /* w += alpha * A * x */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = w[i];                    // local copy of w[i]
        const double *restrict Ap = A[i].data();
        for (int j = 0; j < n; ++j) {
            sum += alpha * Ap[j] * x[j];
        }
        w[i] = sum;                           // write back
    }
}
