durbin:
```cpp
#include <vector>
#include <omp.h>

/* Optimised Durbin kernel – identical public interface. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y)
{
    /* Use raw pointers for speed, keep a single temporary buffer. */
    double *const rptr = r.data();
    double *const yptr = y.data();

    std::vector<double> z(n, 0.0);
    double *const zptr = z.data();

    yptr[0] = -rptr[0];
    double beta  = 1.0;
    double alpha = -rptr[0];

    for (int k = 1; k < n; ++k) {
        /* Update beta (scalars). */
        beta = (1.0 - alpha * alpha) * beta;

        /* Compute sum = Σ_{i=0}^{k-1} r[k-i-1] * y[i]  */
        double sum = 0.0;
#pragma omp parallel for reduction(+:sum) schedule(static)
        for (int i = 0; i < k; ++i) {
            sum += rptr[k - i - 1] * yptr[i];
        }

        /* New reflection coefficient. */
        alpha = -(rptr[k] + sum) / beta;

        /* Update y[0..k-1] using a temporary buffer. */
#pragma omp parallel for schedule(static)
        for (int i = 0; i < k; ++i) {
            zptr[i] = yptr[i] + alpha * yptr[k - i - 1];
        }

#pragma omp parallel for schedule(static)
        for (int i = 0; i < k; ++i) {
            yptr[i] = zptr[i];
        }

        yptr[k] = alpha;
    }
}
