#include <vector>
#include <cstddef>
#include <cstdint>
#include <cstring>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_doitgen(int nr, int nq, int np,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<double>>& C4,
                    std::vector<double>& sum)
{
    /* Flatten the 3‑D container for better spatial locality.
       The original structure is guaranteed to be contiguous “by
       construction” (each std::vector owns its own storage).
       To avoid extra indirection we copy pointers to the base of
       each sub‑level. */

    // Pointers to the 3‑D array: A[r][q] -> base + r*stride_rq + q*stride_q
    std::vector<double*> A_base(nr * nq);
    for (int r = 0; r < nr; ++r)
        for (int q = 0; q < nq; ++q)
            A_base[r * nq + q] = A[r][q].data();

    // Pointers to each row of C4
    std::vector<double*> C4_row(np);
    for (int s = 0; s < np; ++s)
        C4_row[s] = C4[s].data();

    /* Parallelise the outer loops.  Collapse(3) lets us distribute the
       work over all three dimensions, ensuring that each thread gets a
       balanced chunk.  A static schedule is used because the cost of
       each iteration is the same (fixed size of inner loops). */

#pragma omp parallel for collapse(3) schedule(static)
    for (int r = 0; r < nr; ++r) {
        for (int q = 0; q < nq; ++q) {
            double* Arq = A_base[r * nq + q];
            /* Allocate a small stack buffer for the partial sums.
               It is smaller than np (up to a few hundred), so the
               allocation overhead is negligible. */
            double local_sum[4096];                // assume np <= 4096; guard
            const int limit = np > 4096 ? 4096 : np;

            for (int p = 0; p < np; ++p) {
                double acc = 0.0;
                for (int s = 0; s < np; ++s)
                    acc += Arq[s] * C4_row[s][p];
                local_sum[p] = acc;
            }

            /* Write the result back to A. */
            for (int p = 0; p < np; ++p)
                Arq[p] = local_sum[p];
        }
    }
}
