```cpp
#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y)
{
    /* ---------------------------------------------------------------------
       Step 1 – LU decomposition (no pivoting)
       --------------------------------------------------------------------- */
    for (int i = 0; i < n; ++i) {
        double* Ai     = A[i].data();   // pointer to row i
        const double* AiRow = Ai;      // alias used during inner loops

        /* ---- Lower triangle computation -------------------------------- */
        for (int j = 0; j < i; ++j) {
            double w = Ai[j];
            const double* Aj = A[j].data();
            for (int k = 0; k < j; ++k) {
                w -= Ai[k] * Aj[k];
            }
            Ai[j] = w / Aj[j];
        }

        /* ---- Upper triangle computation -------------------------------- */
        for (int j = i; j < n; ++j) {
            double w = Ai[j];
            for (int k = 0; k < i; ++k) {
                w -= Ai[k] * A[k][j];
            }
            Ai[j] = w;
        }
    }

    /* ---------------------------------------------------------------------
       Step 2 – Forward substitution (L * y = b)
       --------------------------------------------------------------------- */
    for (int i = 0; i < n; ++i) {
        double w = b[i];
        const double* Ai = A[i].data();
        for (int j = 0; j < i; ++j) {
            w -= Ai[j] * y[j];
        }
        y[i] = w;
    }

    /* ---------------------------------------------------------------------
       Step 3 – Backward substitution (U * x = y)
       --------------------------------------------------------------------- */
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];
        const double* Ai = A[i].data();
        for (int j = i + 1; j < n; ++j) {
            w -= Ai[j] * x[j];
        }
        x[i] = w / Ai[i];
    }
}
