nussinov:
```cpp
#include <vector>
#include <algorithm>
#include <cstring>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* Original version by Dave Wonnacott at Haverford College <davew@cs.haverford.edu>,
   with help from Allison Lake, Ting Zhou, and Tian Jin,
   based on algorithm by Nussinov, described in Allison Lake's senior thesis. */

void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table)
{
    // Work with raw pointers for maximal speed.
    const int* seqData = seq.data();
    int* tableData = &table[0][0];           // contiguous storage
    const int stride = n;

    #pragma omp parallel for schedule(static)
    for (int i = n-1; i >= 0; --i) {
        int* rowI = tableData + i*stride;
        for (int j = i+1; j < n; ++j) {
            int best = rowI[j-1];
            best = std::max(best, *(tableData + (i+1)*stride + j));
            if (j-1 >= 0 && i+1 < n) {
                int val = *(tableData + (i+1)*stride + (j-1));
                if (i < j-1) val += (seqData[i] + seqData[j] == 3);
                best = std::max(best, val);
            }
            for (int k = i+1; k < j; ++k) {
                int val = *(tableData + i*stride + k) + *(tableData + (k+1)*stride + j);
                if (val > best) best = val;
            }
            rowI[j] = best;
        }
    }
}
