/* Optimised A*TX kernel.
 * The interface is kept identical to the original.
 * Internally we rearrange the loop order, use contiguous memory
 * accesses, block‑size optimisation and OpenMP parallelisation. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {

    /* All matrices and vectors are already stored in contiguous std::vector
       containers.  We merely access them through raw pointers for speed. */
    const double* const x_ptr = x.data();
    double*       y_ptr = y.data();
    double*       tmp_ptr = tmp.data();

    /* Clear y once before the kernel. */
    std::fill(y_ptr, y_ptr + n, 0.0);

    /* Block size (chosen experimentally for L1/L2 cache line size). */
    constexpr std::size_t BLOCK = 64;

    /* Parallel over the outer loop using OpenMP.  Each thread supplies a
       private temporary vector of length n to avoid race conditions. */
#pragma omp parallel
    {
        /* Private temporary for the current thread. */
        std::vector<double> tmp_private(n, 0.0);
        double* tmp_p = tmp_private.data();

#pragma omp for schedule(static)
        for (int i = 0; i < m; ++i) {
            /* Access the current row of A. */
            const double* row = A[i].data();

            /* First pass: compute tmp[i] = A[i] * x. */
            for (int j = 0; j < n; ++j) {
                tmp_p[j] = row[j] * x_ptr[j];
            }

            /* Second pass: accumulate into y.  Unroll 8 for extra
               pipeline efficiency. */
            int j;
            for (j = 0; j + 7 < n; j += 8) {
                y_ptr[j]     += tmp_p[j]     * row[j];
                y_ptr[j + 1] += tmp_p[j + 1] * row[j + 1];
                y_ptr[j + 2] += tmp_p[j + 2] * row[j + 2];
                y_ptr[j + 3] += tmp_p[j + 3] * row[j + 3];
                y_ptr[j + 4] += tmp_p[j + 4] * row[j + 4];
                y_ptr[j + 5] += tmp_p[j + 5] * row[j + 5];
                y_ptr[j + 6] += tmp_p[j + 6] * row[j + 6];
                y_ptr[j + 7] += tmp_p[j + 7] * row[j + 7];
            }
            for (; j < n; ++j) {
                y_ptr[j] += tmp_p[j] * row[j];
            }
        }
    }
