/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_bicg(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& s,
                 std::vector<double>& q,
                 std::vector<double>& p,
                 std::vector<double>& r) {
    /* Zero s in a single thread (cheap, avoids data race) */
    std::fill(s.begin(), s.end(), 0.0);

    /* Compute the sum of all elements of p once – reused for every i */
    double sum_p = 0.0;
    #pragma omp simd reduction(+:sum_p)
    for (int j = 0; j < m; ++j) sum_p += p[j];

    /* The main work: loop over rows i.
       We can parallelise the outer loop safely because only
       s[j] is written in parallel (atomic add) and each i writes a unique q[i]. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double row_sum = 0.0;           // accumulate sum of A[i][j]
        const std::vector<double>& Arow = A[i];  // access once

        /* Inner loop over columns j
           Note: we use SIMD directives to let the compiler vectorise
           and we rely on the atomic add for s[j]. */
        #pragma omp simd linear(j)
        for (int j = 0; j < m; ++j) {
            double a = Arow[j];
            row_sum += a;
            /* Rely on atomic add for s[j] to avoid race conditions */
            #pragma omp atomic
            s[j] += r[i] * a;
        }

        /* Compute q[i] from the row sum and the pre‑computed sum_p */
        q[i] = row_sum + sum_p;
    }
}
