void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Pre‑compute pointers to each row to avoid bounds checks and index
    // calculations inside the innermost loops.
    std::vector<int*> rows(n);
    for (int i = 0; i < n; ++i) {
        rows[i] = path[i].data();
    }

    // The k dimension must be processed sequentially because each update
    // depends on the already updated values for that k.
    for (int k = 0; k < n; ++k) {
        int* rowk = rows[k];
        // Parallelise over i for each fixed k.
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < n; ++i) {
            int* rowi   = rows[i];
            int  pathik = rowi[k];          // value at (i,k) before this iteration

            for (int j = 0; j < n; ++j) {
                int candidate = rowk[j] + pathik;
                if (rowi[j] > candidate) {
                    rowi[j] = candidate;
                }
            }
        }
    }
}
