#include <vector>
#include <cmath>
#include <omp.h>

/* ------------------------------------------------------------
   Kernel that computes the pairwise correlation matrix.
   The function keeps the exact semantics of the reference
   implementation while improving performance with
   cache‑friendly data layout and OpenMP parallelism.
   ------------------------------------------------------------ */

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev)
{
    // Flatten the data matrix into column major layout:
    //   flat[col * n + row]  ==  data[row][col]
    std::vector<double> flat(m * n);
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            flat[j * n + i] = data[i][j];

    const double eps = 0.1;
    const double inv_n = 1.0 / n;
    const double sqrt_n = std::sqrt(static_cast<double>(n));

    /* Compute column means (O(m*n)) */
    #pragma omp parallel for
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) sum += flat[j * n + i];
        mean[j] = sum * inv_n;
    }

    /* Compute column standard deviations (O(m*n)) */
    #pragma omp parallel for
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        const double mu = mean[j];
        for (int i = 0; i < n; ++i) {
            double diff = flat[j * n + i] - mu;
            sum += diff * diff;
        }
        stddev[j] = std::sqrt(sum * inv_n);
        if (stddev[j] <= eps) stddev[j] = 1.0;
    }

    /* Normalize data: subtract mean and divide by (sqrt(n)*stddev) */
    #pragma omp parallel for collapse(2)
    for (int j = 0; j < m; ++j) {
        const double denom = sqrt_n * stddev[j];
        for (int i = 0; i < n; ++i)
            flat[j * n + i] = (flat[j * n + i] - mean[j]) / denom;
    }

    /* Compute correlation matrix */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k)
                sum += flat[i * n + k] * flat[j * n + k];
            corr[i][j] = corr[j][i] = sum;
        }
    }
}
```
