/* 2‑D Jacobi solver kernel.
    A and B must have dimensions [n][n] and be 1‑based in the
    original code (i.e. the valid indices are 1..n‑2 inclusive).
    The function uses a flattened array representation for
    maximum cache performance and parallelises the inner loops with
    OpenMP.  The arithmetic is unchanged so the numerical result is
    identical to the reference implementation. */
inline void kernel_jacobi_2d(int tsteps,
                             int n,
                             std::vector<std::vector<double>>& A,
                             std::vector<std::vector<double>>& B)
{
    /* Flatten the 2‑D vectors into 1‑D to eliminate pointer indirection
       and enable contiguous memory accesses.  We keep the same
       logical layout, so index (i,j) maps to offset i*n + j. */
    const int size = n * n;
    std::vector<double> flatA(size), flatB(size);
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            flatA[i * n + j] = A[i][j];
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            flatB[i * n + j] = B[i][j];

    const double w = 0.2;
    /* ----------------------------------------------------------------*/
    /* Main time‑stepping loop.  The outer loop is not parallelised
       because each timestep depends on the previous one.  The inner
       2‑D update loops are parallelised over the outermost dimension
       (rows) as this keeps the critical section small and respects
       the barrier required at the end of each stage.                        */
    /* ----------------------------------------------------------------*/
    for (int t = 0; t < tsteps; ++t) {
        /* Update B from A */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            int idx = i * n + 1;          // start j=1
            for (int j = 1; j < n - 1; ++j, ++idx) {
                flatB[idx] = w * ( flatA[idx]                     // A[i][j]
                                 + flatA[idx-1]                   // A[i][j-1]
                                 + flatA[idx+1]                   // A[i][j+1]
                                 + flatA[idx+n]                   // A[i+1][j]
                                 + flatA[idx-n] );                // A[i-1][j]
            }
        }

        /* Update A from B */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            int idx = i * n + 1;          // start j=1
            for (int j = 1; j < n - 1; ++j, ++idx) {
                flatA[idx] = w * ( flatB[idx]                     // B[i][j]
                                 + flatB[idx-1]                   // B[i][j-1]
                                 + flatB[idx+1]                   // B[i][j+1]
                                 + flatB[idx+n]                   // B[i+1][j]
                                 + flatB[idx-n] );                // B[i-1][j]
            }
        }
    }

    /* Copy results back into the original 2‑D containers */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            A[i][j] = flatA[i * n + j];
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            B[i][j] = flatB[i * n + j];
}
