        for (; j <= n-4; j += 4) {
            __m256d a = _mm256_load_pd(&ApRow[j]);
            __m256d b = _mm256_load_pd(&y1[j]);
            __m256d prod = _mm256_mul_pd(a, b);
            __m256d hi = _mm256_hadd_pd(prod, prod);
            __m256d lo = _mm256_hadd_pd(hi, hi);
            sum += _mm256_cvtsd_f64(lo);
