    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        int j = 0;
        for (; j <= n-4; j += 4) {
            __m256d a = _mm256_set_pd(Ap[j+3][i], Ap[j+2][i], Ap[j+1][i], Ap[j][i]);
            __m256d b = _mm256_load_pd(&y2[j]);
            __m256d prod = _mm256_mul_pd(a, b);
            __m256d hi = _mm256_hadd_pd(prod, prod);
            __m256d lo = _mm256_hadd_pd(hi, hi);
            sum += _mm256_cvtsd_f64(lo);
        }
        for (; j < n; ++j) sum += Ap[j][i] * y2[j];
        x2p[i] += sum;
    }
}
