static inline std::size_t idx(std::size_t i, std::size_t j, std::size_t k,
                              std::size_t n)
{
    return (i * n + j) * n + k;
}

void kernel_heat_3d(int tsteps,
                    int n,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<std::vector<double>>>& B)
{
    // Flatten the 3‑D std::vector into 1‑D arrays for fast access
    const std::size_t N = static_cast<std::size_t>(n);
    const std::size_t tot = N * N * N;
    std::vector<double> Af(tot), Bf(tot);

    // Copy original data into flat arrays
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            for (int k = 0; k < n; ++k)
                Af[idx(i,j,k,N)] = A[i][j][k];

    const double coef = 0.125;
    const int start = 1, end = n-2;   // interior indices

    for (int t = 1; t <= tsteps; ++t) {
        // B[i][j][k] = f(A)
        #pragma omp parallel for collapse(3)
        for (int i = start; i <= end; ++i) {
            for (int j = start; j <= end; ++j) {
                for (int k = start; k <= end; ++k) {
                    std::size_t center = idx(i,j,k,N);
                    double val = A[i][j][k] + 0.0;   // dummy to keep same order
                    val += coef * (  A[i+1][j][k] - 2.0*A[i][j][k] + A[i-1][j][k]
                                   + A[i][j+1][k] - 2.0*A[i][j][k] + A[i][j-1][k]
                                   + A[i][j][k+1] - 2.0*A[i][j][k] + A[i][j][k-1] );
                    Bf[center] = val;
                }
            }
        }

        // A[i][j][k] = f(B)
        #pragma omp parallel for collapse(3)
        for (int i = start; i <= end; ++i) {
            for (int j = start; j <= end; ++j) {
                for (int k = start; k <= end; ++k) {
                    std::size_t center = idx(i,j,k,N);
                    double val = B[i][j][k] + 0.0;   // dummy
                    val += coef * (  B[i+1][j][k] - 2.0*B[i][j][k] + B[i-1][j][k]
                                   + B[i][j+1][k] - 2.0*B[i][j][k] + B[i][j-1][k]
                                   + B[i][j][k+1] - 2.0*B[i][j][k] + B[i][j][k-1] );
                    Af[center] = val;
                }
            }
        }
    }

    // Copy results back into original 3‑D vectors
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            for (int k = 0; k < n; ++k)
                A[i][j][k] = Af[idx(i,j,k,N)];
