#include <cmath>
#include <vector>
#include <cstddef>
#include <omp.h>

/* QR Decomposition with Modified Gram Schmidt:
 * http://www.inf.ethz.ch/personal/gander/
 * The function signature (m, n, A, R, Q) is kept for compatibility
 * with the original code and the harness.  Inside the kernel we
 * convert the logical 2‑D access into flat pointer arithmetic to
 * achieve cache friendliness.  OpenMP parallelism is applied to every
 * loop whose iterations are independent.  The compiler will keep
 * the original static –O2 optimisation level. */

static constexpr std::size_t BLOCK = 64;  // tune for L1/L2 cache

inline double dot_mul(const double *x, const double *y, std::size_t len)
{
    double sum = 0.0;
    std::size_t i = 0;
    for (; i + 7 < len; i += 8) {
        sum += x[i]*y[i]   + x[i+1]*y[i+1] + x[i+2]*y[i+2] + x[i+3]*y[i+3]
             + x[i+4]*y[i+4] + x[i+5]*y[i+5] + x[i+6]*y[i+6] + x[i+7]*y[i+7];
    }
    for (; i < len; ++i) sum += x[i]*y[i];
    return sum;
}

void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q)
{
    const std::size_t stride = static_cast<std::size_t>(m);

    // Work on flat pointers for better locality
    std::vector<double> A_flat(m * n);
    std::vector<double> Q_flat(m * n);
    std::vector<double> R_diag(n);
    std::vector<std::vector<double>> R_flat(n, std::vector<double>(n, 0.0));

    // Copy A into flat buffer
#pragma omp parallel for schedule(static, BLOCK)
    for (int j = 0; j < n; ++j)
        for (int i = 0; i < m; ++i)
            A_flat[i + j*stride] = A[i][j];

    for (int k = 0; k < n; ++k) {
        // compute norm
        const double *col = &A_flat[k * stride];
        double nrm = dot_mul(col, col, static_cast<std::size_t>(m));
        double rkk = std::sqrt(nrm);
        R_diag[k] = rkk;

        // Q column
#pragma omp parallel for schedule(static, BLOCK)
        for (int i = 0; i < m; ++i)
            Q_flat[i + k*stride] = col[i] / rkk;

        // compute remaining columns
        for (int j = k + 1; j < n; ++j) {
            double rkj = 0.0;
            const double *colj = &A_flat[j * stride];
#pragma omp parallel for reduction(+:rkj) schedule(static, BLOCK)
            for (int i = 0; i < m; ++i)
                rkj += Q_flat[i + k*stride] * colj[i];

            R_flat[k][j] = rkj;

#pragma omp parallel for schedule(static, BLOCK)
            for (int i = 0; i < m; ++i)
                A_flat[i + j*stride] -= Q_flat[i + k*stride] * rkj;
        }
    }

    // Scatter results back into the 2‑D containers
#pragma omp parallel for schedule(static, BLOCK)
    for (int j = 0; j < n; ++j)
        for (int i = 0; i < m; ++i)
            Q[i][j] = Q_flat[i + j*stride];

#pragma omp parallel for schedule(static, BLOCK)
    for (int i = 0; i < n; ++i)
        for (int j = i; j < n; ++j)
            R[i][j] = R_flat[i][j];

#pragma omp parallel for schedule(static, BLOCK)
    for (int i = 0; i < n; ++i)
        R[i][i] = R_diag[i];
}
