#include <vector>
#include <cstddef>
#include <omp.h>

/*=============================================================================
 * Optimised version of the ADI kernel
 *=============================================================================
 * The original interfaces are preserved, but the implementation uses
 * contiguous storage (row-major 1‑D) and OpenMP pragmas for full
 * parallelisation.
 *=============================================================================*/

static inline double *row(std::vector<std::vector<double>>& a, std::size_t r)
{
    return a[r].data();
}

// Helper to compute the linear index in flattened 2‑D storage
static inline std::size_t idx(std::size_t i, std::size_t j, std::size_t n)
{
    return i * n + j;
}

// Flatten a 2‑D std::vector for contiguous access.  The caller must
// ensure that the underlying container is contiguous (which it is in
// the test harness).
template<class T>
static inline std::vector<T>& flatten(std::vector<std::vector<T>>& v)
{
    std::size_t n = v.size();
    v.resize(n * n);
    for (std::size_t i = 0; i < n; ++i)
        std::copy(v[i].data(), v[i].data() + n, &v[0][idx(i,0,n)]);
    return v;
}

void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u_,
                std::vector<std::vector<double>>& v_,
                std::vector<std::vector<double>>& p_,
                std::vector<std::vector<double>>& q_) {

    /* Convert all buffers to flat contiguous arrays */
    auto& u = flatten(u_);
    auto& v = flatten(v_);
    auto& p = flatten(p_);
    auto& q = flatten(q_);

    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1 = 2.0;
    const double B2 = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a = -mul1 / 2.0;
    const double b = 1.0 + mul1;
    const double c = a;
    const double d = -mul2 / 2.0;
    const double e = 1.0 + mul2;
    const double f = d;

    /* Main time loop */
    for (int t = 1; t <= tsteps; ++t) {
        /* First sweep (v‑direction) */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n-1; ++i) {
            double* vp  = &v[idx(0,i,n)];
            double* pp  = &p[idx(0,i,n)];
            double* qp  = &q[idx(0,i,n)];
            double* ui_ = &u[idx(i,n, n)];
            double* ui_m1 = &u[idx(i-1,n, n)];
            double* ui_p1 = &u[idx(i+1,n, n)];

            vp[0] = 1.0;
            pp[0] = 0.0;
            qp[0] = vp[0];

            double denom = b;
            for (int j = 1; j < n-1; ++j) {
                /* p[i][j] */
                double p_ij = -c / (a * p[j-1] + b);
                pp[j] = p_ij;

                /* q[i][j] */
                double q_ij = (-d * ui_m1[j-1] + (1.0 + 2.0 * d) * ui_m1[j] -
                               f * ui_m1[j+1] - a * qp[j-1]) / (a * p[j-1] + b);
                qp[j] = q_ij;
            }

            vp[n-1] = 1.0;
            for (int j = n-2; j >= 1; --j) {
                vp[j] = pp[j] * vp[j+1] + qp[j];
            }
        }

        /* Second sweep (u‑direction) */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n-1; ++i) {
            double* ui  = &u[idx(0,i,n)];
            double* pp  = &p[idx(0,i,n)];
            double* qp  = &q[idx(0,i,n)];
            double* vp_ = &v[idx(i,n, n)];
            double* vp_m1 = &v[idx(i-1,n, n)];
            double* vp_p1 = &v[idx(i+1,n, n)];

            ui[0] = 1.0;
            pp[0] = 0.0;
            qp[0] = ui[0];

            for (int j = 1; j < n-1; ++j) {
                double p_ij = -f / (d * p[j-1] + e);
                pp[j] = p_ij;

                double q_ij = (-a * vp_m1[j] + (1.0 + 2.0 * a) * vp_m1[j] -
                               c * vp_p1[j] - d * qp[j-1]) / (d * p[j-1] + e);
                qp[j] = q_ij;
            }

            ui[n-1] = 1.0;
            for (int j = n-2; j >= 1; --j) {
                ui[j] = pp[j] * ui[j+1] + qp[j];
            }
        }
    }
}
