```cpp
#include <cmath>
#include <vector>
#include <omp.h>

/* Optimised Deriche filter kernel */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* ----------------------------------------------------------
       Pre‑compute constants only once
       ---------------------------------------------------------- */
    const float exp_alpha   = std::exp(-alpha);
    const float exp_2alpha  = exp_alpha * exp_alpha;
    const float numerator   = exp_alpha * (1.0f - exp_alpha);
    const float denom       = 1.0f + 2.0f * static_cast<float>(alpha) * exp_alpha - exp_2alpha;
    const float k           = 1.0f - numerator / denom;

    const float a1 =  k;
    const float a2 =  k * exp_alpha * (static_cast<float>(alpha) - 1.0f);
    const float a3 =  k * exp_alpha * (static_cast<float>(alpha) + 1.0f);
    const float a4 = -k * exp_2alpha;

    const float a5 =  a1;
    const float a6 =  a2;
    const float a7 =  a3;
    const float a8 =  a4;

    const float b1 = std::pow(2.0f, -static_cast<float>(alpha));
    const float b2 = -exp_2alpha;

    const float c1 = 1.0f;
    const float c2 = 1.0f;

    /* ----------------------------------------------------------
       1st pass : row – forward filtering (y1)
       ---------------------------------------------------------- */
    #pragma omp parallel for
    for (int i = 0; i < w; ++i) {
        const float* in  = imgIn[i].data();
              float* y1p = y1[i].data();

        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;

        for (int j = 0; j < h; ++j) {
            const float x = in[j];
            const float y = a1 * x + a2 * xm1 + b1 * ym1 + b2 * ym2;
            y1p[j] = y;
            xm1 = x;
            ym2 = ym1;
            ym1 = y;
        }
    }

    /* ----------------------------------------------------------
       1st pass : row – backward filtering (y2)
       ---------------------------------------------------------- */
    #pragma omp parallel for
    for (int i = 0; i < w; ++i) {
        const float* in  = imgIn[i].data();
              float* y2p = y2[i].data();

        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;

        for (int j = h-1; j >= 0; --j) {
            const float x = in[j];
            const float y = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            y2p[j] = y;
            xp2 = xp1;
            xp1 = x;
            yp2 = yp1;
            yp1 = y;
        }
    }

    /* ----------------------------------------------------------
       Combine row results into intermediate image
       ---------------------------------------------------------- */
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[i][j] = c1 * (y1[i][j] + y2[i][j]);

    /* ----------------------------------------------------------
       2nd pass : column – forward filtering (y1)
       ---------------------------------------------------------- */
    #pragma omp parallel for
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;

        for (int i = 0; i < w; ++i) {
            const float x = imgOut[i][j];
            const float y = a5 * x + a6 * tm1 + b1 * ym1 + b2 * ym2;
            y1[i][j] = y;
            tm1 = x;
            ym2 = ym1;
            ym1 = y;
        }
    }

    /* ----------------------------------------------------------
       2nd pass : column – backward filtering (y2)
       ---------------------------------------------------------- */
    #pragma omp parallel for
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;

        for (int i = w-1; i >= 0; --i) {
            const float x = imgOut[i][j];
            const float y = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            y2[i][j] = y;
            tp2 = tp1;
            tp1 = x;
            yp2 = yp1;
            yp1 = y;
        }
    }

    /* ----------------------------------------------------------
       Final combination
       ---------------------------------------------------------- */
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[i][j] = c2 * (y1[i][j] + y2[i][j]);
}
